<script src="https://download.agora.io/sdk/release/AgoraRTC_N-4.22.2.js"></script><script src="https://cdn.jsdelivr.net/npm/livekit-client/dist/livekit-client.umd.min.js"></script>
<script>
(function(){var modal=document.getElementById('bdlivePreviewModal'),closeBtn=document.getElementById('previewClose'),statusEl=document.getElementById('previewStatus'),videoStage=document.getElementById('previewVideoStage'),audioStage=document.getElementById('previewAudioStage'),audioElements=document.getElementById('previewAudioElements'),agoraClient=null,livekitRoom=null;function setStatus(m,e){statusEl.textContent=m;statusEl.className='preview-status'+(e?' preview-error':'')}function openModal(){modal.classList.add('active');modal.setAttribute('aria-hidden','false')}async function cleanup(){try{if(agoraClient){(agoraClient.remoteUsers||[]).forEach(function(u){if(u.videoTrack){try{u.videoTrack.stop()}catch(e){}} if(u.audioTrack){try{u.audioTrack.stop()}catch(e){}}});await agoraClient.leave()}}catch(e){}agoraClient=null;try{if(livekitRoom){livekitRoom.disconnect()}}catch(e){}livekitRoom=null;videoStage.innerHTML='Preview stopped';audioElements.innerHTML=''}async function closeModal(){await cleanup();modal.classList.remove('active');modal.setAttribute('aria-hidden','true')}function meta(d){var r=d.room;document.getElementById('previewTitle').textContent=r.host_name+' live preview';document.getElementById('previewProvider').textContent=d.provider==='agora'?'Agora video':'LiveKit audio';document.getElementById('previewChannel').textContent=r.channelName;document.getElementById('previewHostId').textContent=r.host_id;document.getElementById('previewAudience').textContent=r.audience_count;document.getElementById('previewSeats').textContent=r.active_seats+'/'+r.seat_limit;document.getElementById('previewHostName').textContent=r.host_name;document.getElementById('previewRoomName').textContent=r.channelName;document.getElementById('previewSeatText').textContent=r.active_seats+'/'+r.seat_limit;document.getElementById('previewHostAvatar').src=r.host_profile?'/'+String(r.host_profile).replace(/^\/+/, ''):'/store/profile/default.png';var g=document.getElementById('previewSeatGrid');g.innerHTML='';var lim=Math.max(r.seat_limit||0,r.active_seats||0,1);for(var i=1;i<=lim;i++){var s=document.createElement('div');s.className='seat-box'+(i<=r.active_seats?' active':'');s.innerHTML='<strong>'+i+'</strong><span>'+(i<=r.active_seats?'Busy':'Open')+'</span>';g.appendChild(s)}}async function startAgora(d){audioStage.style.display='none';videoStage.style.display='flex';videoStage.innerHTML='Connecting Agora video...';if(!window.AgoraRTC){throw new Error('Agora web SDK not loaded')}agoraClient=AgoraRTC.createClient({mode:'live',codec:'vp8'});agoraClient.setClientRole('audience');agoraClient.on('user-published',async function(u,t){await agoraClient.subscribe(u,t);if(t==='video'){videoStage.innerHTML='<div id="agoraRemoteVideo" style="width:100%;height:100%"></div>';u.videoTrack.play('agoraRemoteVideo')}if(t==='audio'){u.audioTrack.play()}});await agoraClient.join(d.agora.appId,d.agora.channelName,d.agora.token,d.agora.uid);setStatus('Agora video preview connected. Waiting for host media if screen is empty.',false)}async function startLiveKit(d){videoStage.style.display='none';audioStage.style.display='flex';if(!window.LivekitClient){throw new Error('LiveKit web SDK not loaded')}livekitRoom=new LivekitClient.Room({adaptiveStream:true,dynacast:true});livekitRoom.on(LivekitClient.RoomEvent.TrackSubscribed,function(track){if(track.kind==='audio'){audioElements.appendChild(track.attach())}});await livekitRoom.connect(d.livekit.url,d.livekit.token);setStatus('LiveKit audio preview connected. Seat counter loaded from server data.',false)}async function loadPreview(url){await cleanup();openModal();videoStage.style.display='flex';audioStage.style.display='none';videoStage.innerHTML='Loading room data...';setStatus('Requesting preview token...',false);var res=await fetch(url,{headers:{'Accept':'application/json'},credentials:'same-origin'});var d=await res.json();if(!res.ok||!d.success){throw new Error(d.message||'Preview request failed')}meta(d);if(d.provider==='agora'){await startAgora(d)}else{await startLiveKit(d)}}document.querySelectorAll('.live-preview-btn').forEach(function(btn){btn.addEventListener('click',function(){loadPreview(btn.getAttribute('data-preview-url')).catch(function(e){openModal();setStatus(e.message,true);videoStage.style.display='flex';audioStage.style.display='none';videoStage.innerHTML='Preview unavailable'})})});closeBtn.addEventListener('click',closeModal);modal.addEventListener('click',function(e){if(e.target===modal){closeModal()}});document.addEventListener('keydown',function(e){if(e.key==='Escape'&&modal.classList.contains('active')){closeModal()}})})();
</script>
